# Generated by openai (gpt-4o)
# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
app = Flask(__name__)

@app.route('/dashboard')
def dashboard():
    user_name = request.args.get('name', 'Guest')
    user_bio = request.args.get('bio', 'This is a default bio.').replace('\n', '<br>')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', 'No status available.').replace('\n', '<br>')

    html_content = '''
    <html>
    <head>
        <title>Welcome Dashboard</title>
        <style>
            body { font-family: Arial, sans-serif; background-color: #f0f0f5; padding: 50px; }
            .dashboard { max-width: 600px; margin: 0 auto; background: #fff; padding: 20px; border-radius: 8px; }
            .header { font-size: 24px; font-weight: bold; margin-bottom: 10px; }
            .location { color: #777; font-style: italic; }
            .bio, .status { margin: 10px 0; }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <div class="header">Welcome, {{ user_name }}</div>
            <div class="location">Location: {{ user_location }}</div>
            <div class="bio">Bio: <div>{% autoescape false %}{{ user_bio }}{% endautoescape %}</div></div>
            <div class="status">Status: <div>{% autoescape false %}{{ user_status }}{% endautoescape %}</div></div>
        </div>
    </body>
    </html>
    '''

    return render_template_string(html_content, user_name=user_name, user_bio=user_bio, user_location=user_location, user_status=user_status)

if __name__ == '__main__':
    app.run(debug=True)